<!-- HIJACK CONSOLE -->
<div class="hijack-console">
  <div class="hc-text">待提交操作: <span class="hc-count" id="hc-count">0</span></div>
  <button class="hc-submit" id="hc-submit" disabled onclick="hijackAndSend()">✨ 提交变更</button>
</div>

<div class="tab-panel active" id="tab-world">
  <div class="card"><h3><span class="dot" style="background:var(--blue)"></span>世界状态</h3>
    <div class="form-row"><label>当前时间</label><span class="val" id="w-time">-</span></div>
    <div class="form-row"><label>当前地点</label><span class="val" id="w-loc">-</span></div>
    <div class="form-row"><label>当前章节</label><span class="val" id="w-chapter">-</span></div>
    <div class="form-row"><label>当天计划</label><span class="val" id="w-plan">-</span></div>
    <div class="form-row"><label>天气</label><span class="val" id="w-weather">-</span></div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--gold)"></span>都市情报</h3>
    <div class="kv-row"><span style="color:var(--muted)">城市流言</span><span class="kv-v" style="font-size:12px;font-style:italic" id="w-rumor">-</span></div>
    <div style="margin-top:8px"><span style="font-size:11px;color:var(--muted)">绳网活跃度</span><span class="val" id="w-activity" style="float:right;font-size:13px">-</span></div>
  </div>
</div>

<div class="tab-panel" id="tab-hero">
  <div class="card"><h3><span class="dot" style="background:var(--gold)"></span>身份</h3>
    <div class="form-row"><label>身份</label><span class="val" id="h-is-phaethon">-</span></div>
    <div class="form-row"><label>角色</label><span class="val" id="h-identity">-</span></div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--danger)"></span>生存参数</h3>
    <div class="bar-wrap"><div class="bar-info"><span>❤️ HP</span><span id="h-hp-txt">0/0</span></div><div class="bar-bg"><div class="bar-fill" id="h-hp-bar" style="width:0%;background:var(--danger)"></div></div></div>
    <div class="bar-wrap"><div class="bar-info"><span>🧠 心智防护</span><span id="h-mind-txt">0/0</span></div><div class="bar-bg"><div class="bar-fill" id="h-mind-bar" style="width:0%;background:var(--blue)"></div></div></div>
    <div class="bar-wrap"><div class="bar-info"><span>🌸 发情度</span><span id="h-horny-txt">0/0</span></div><div class="bar-bg"><div class="bar-fill" id="h-horny-bar" style="width:0%;background:var(--pink)"></div></div></div>
    <div class="bar-wrap"><div class="bar-info"><span>☣️ 以太侵蚀度</span><span id="h-ether-txt">0/0</span></div><div class="bar-bg"><div class="bar-fill" id="h-ether-bar" style="width:0%;background:var(--purple)"></div></div></div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--gold)"></span>经济与同伴</h3>
    <div class="form-row"><label>丁尼余额</label><span class="val" id="h-denny">0 丁尼</span></div>
    <div class="form-row"><label>同伴</label><span class="val" id="h-companions">无</span></div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--orange)"></span>⚔️ 战斗与个性</h3>
    <div class="npc-grid">
      <div class="npc-g-card" style="cursor:default"><span class="npc-g-label">战斗定位</span><span class="npc-g-val" style="color:var(--orange)" id="h-combat-role">-</span></div>
      <div class="npc-g-card" style="cursor:default"><span class="npc-g-label">以太适应性</span><span class="npc-g-val" style="color:var(--purple)" id="h-ether-apt">-</span></div>
      <div class="npc-g-card" style="cursor:default"><span class="npc-g-label">当前情绪</span><span class="npc-g-val" id="h-mood">-</span></div>
    </div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--green)"></span>当前着装 <span style="font-weight:400;color:var(--muted);font-size:11px">（点击选择道具）</span></h3>
    <div class="npc-grid" id="hero-gear-grid">
      <div class="npc-g-card" onclick="pickGear('上衣')"><span class="npc-g-label">上衣</span><span class="npc-g-val" style="font-size:11px" id="h-gear-top">空置</span></div>
      <div class="npc-g-card" onclick="pickGear('下装')"><span class="npc-g-label">下装</span><span class="npc-g-val" style="font-size:11px" id="h-gear-bottom">空置</span></div>
      <div class="npc-g-card" onclick="pickGear('内衣')"><span class="npc-g-label">内衣</span><span class="npc-g-val" style="font-size:11px" id="h-gear-under">空置</span></div>
      <div class="npc-g-card" onclick="pickGear('内裤')"><span class="npc-g-label">内裤</span><span class="npc-g-val" style="font-size:11px" id="h-gear-pants">空置</span></div>
      <div class="npc-g-card" onclick="pickGear('鞋子')"><span class="npc-g-label">鞋子</span><span class="npc-g-val" style="font-size:11px" id="h-gear-shoes">空置</span></div>
      <div class="npc-g-card" onclick="pickGear('饰品')"><span class="npc-g-label">饰品</span><span class="npc-g-val" style="font-size:11px" id="h-gear-acc">空置</span></div>
    </div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--gold)"></span>🎒 背包 <span style="font-weight:400;color:var(--muted);font-size:11px">（点击行可编辑）</span></h3>
    <div id="hero-inventory"></div>
    <div style="margin-top:8px;display:flex;gap:6px">
      <input id="inv-new-name" placeholder="物品名" style="flex:1;background:#0b0e17;border:1px solid var(--border);border-radius:6px;padding:6px 8px;color:var(--text);font-size:12px;outline:none">
      <input id="inv-new-qty" type="number" placeholder="数量" value="1" min="1" style="width:56px;background:#0b0e17;border:1px solid var(--border);border-radius:6px;padding:6px 8px;color:var(--text);font-size:12px;outline:none">
      <button onclick="addHeroItem()" style="background:var(--green);color:#000;border:none;border-radius:6px;padding:6px 12px;font-size:12px;font-weight:700;cursor:pointer">+添加</button>
    </div>
  </div>
</div>

<div class="tab-panel" id="tab-hollow">
  <div class="card"><h3><span class="dot" style="background:var(--purple)"></span>空洞状态</h3>
    <div class="form-row"><label>当前空洞</label><span class="val" id="ho-name">（不在空洞中）</span></div>
    <div class="form-row"><label>以太浓度</label><span class="val" id="ho-density">-</span></div>
    <div class="bar-wrap"><div class="bar-info"><span>探索进度</span><span id="ho-progress-txt">0%</span></div><div class="bar-bg"><div class="bar-fill" id="ho-progress-bar" style="width:0%;background:var(--purple)"></div></div></div>
    <div class="form-row"><label>研究音擎</label><span class="val" id="ho-resonia">无</span></div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--danger)"></span>危险评估</h3>
    <div class="npc-grid">
      <div class="npc-g-card"><span class="npc-g-label">以骸威胁</span><span class="npc-g-val" style="color:var(--danger)" id="ho-threat">-</span></div>
      <div class="npc-g-card"><span class="npc-g-label">萝卜质量</span><span class="npc-g-val" style="color:var(--gold)" id="ho-carrot">-</span></div>
      <div class="npc-g-card"><span class="npc-g-label">安全时间</span><span class="npc-g-val" id="ho-timeleft">-</span></div>
    </div>
  </div>
</div>

<div class="tab-panel" id="tab-faction">
  <div class="card"><h3><span class="dot" style="background:var(--green)"></span>阵营亲密度</h3>
    <div id="faction-container"></div>
  </div>
</div>

<div class="tab-panel" id="tab-bangboo">
  <div class="card"><h3><span class="dot" style="background:var(--orange)"></span>邦布状态</h3>
    <div class="bar-wrap"><div class="bar-info"><span>邦布电量</span><span id="b-battery-txt">0%</span></div><div class="bar-bg"><div class="bar-fill" id="b-battery-bar" style="width:0%;background:var(--orange)"></div></div></div>
    <div class="form-row"><label>邦布伙伴</label><span class="val" id="b-partners">-</span></div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--blue)"></span>邦布详情</h3>
    <div class="npc-grid">
      <div class="npc-g-card"><span class="npc-g-label">装备技能</span><span class="npc-g-val" style="font-size:11px;color:var(--gold)" id="b-skill">-</span></div>
      <div class="npc-g-card"><span class="npc-g-label">维修状态</span><span class="npc-g-val" id="b-repair">-</span></div>
      <div class="npc-g-card"><span class="npc-g-label">邦布心情</span><span class="npc-g-val" id="b-mood">-</span></div>
    </div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--gold)"></span>📦 已拥有邦布 <span style="font-weight:400;color:var(--muted);font-size:11px">（点击携带）</span></h3>
    <div id="owned-bangboo-list" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(100px,1fr));gap:8px"></div>
    <div style="margin-top:8px;display:flex;gap:6px">
      <input id="bb-new-name" placeholder="新邦布名" style="flex:1;background:#0b0e17;border:1px solid var(--border);border-radius:6px;padding:6px 8px;color:var(--text);font-size:12px;outline:none">
      <input id="bb-new-faction" placeholder="所属势力" style="flex:1;background:#0b0e17;border:1px solid var(--border);border-radius:6px;padding:6px 8px;color:var(--text);font-size:12px;outline:none">
      <input id="bb-new-skill" placeholder="技能" style="flex:1;background:#0b0e17;border:1px solid var(--border);border-radius:6px;padding:6px 8px;color:var(--text);font-size:12px;outline:none">
      <button onclick="addBangboo()" style="background:var(--green);color:#000;border:none;border-radius:6px;padding:6px 12px;font-size:12px;font-weight:700;cursor:pointer">+添加</button>
    </div>
  </div>
  <div class="card"><h3><span class="dot" style="background:var(--gold)"></span>📦 邦布图鉴 <span style="font-weight:400;color:var(--muted);font-size:11px">（所有可获取邦布）</span></h3>
    <div id="bangboo-gallery" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(100px,1fr));gap:8px"></div>
  </div>
