<div class="tab-panel" id="tab-npc">
  <div class="card" style="margin-bottom:8px"><h3><span class="dot" style="background:var(--pink)"></span>社交详情</h3></div>
  <div id="npc-container"></div>
</div>

<div class="tab-panel" id="tab-quest">
  <div class="card" style="margin-bottom:8px"><h3><span class="dot" style="background:var(--orange)"></span>任务信息</h3></div>
  <div id="quest-container"></div>
</div>

<div class="footer">绝区零 RPG · 信息面板 v4.4 · 事件驱动刷新</div>
</div>

<script>
const LEVEL_NAMES=['敌对','冷淡','中立','友好','亲密','热恋'];
function getLevel(v){const n=parseInt(v)||0;if(n<=-51)return LEVEL_NAMES[0];if(n<=-11)return LEVEL_NAMES[1];if(n<=10)return LEVEL_NAMES[2];if(n<=50)return LEVEL_NAMES[3];if(n<=80)return LEVEL_NAMES[4];return LEVEL_NAMES[5]}
function getProp(obj,path,def){var keys=path.split('.');var r=obj;for(var i=0;i<keys.length;i++){if(r&&typeof r==='object'&&keys[i]in r)r=r[keys[i]];else return def}return r!==undefined?r:def}
window.npcImageCache={};window.cachedData=null;
window.pendingActions=[];
function updateHijack(){document.getElementById('hc-count').innerText=window.pendingActions.length;document.getElementById('hc-submit').disabled=window.pendingActions.length===0}
window.hijackAndSend=function(){if(window.pendingActions.length===0)return;var lines=window.pendingActions.map(function(a){return a.desc}).join('\n');if(typeof triggerSlash==='function')triggerSlash('/send 请执行以下操作：\n'+lines+'|/trigger');else alert('待发送:\n'+lines);window.pendingActions=[];updateHijack()}
