window.pickGear=function(slot){
  var sd=window.cachedData;var inv=getProp(sd,'主角.背包',getProp(sd,'主角.背包',{}));var items=[{name:'卸下(空置)',desc:'移除当前装备'}];
  if(typeof inv==='object'){var invKeys=Object.keys(inv);for(var i=0;i<invKeys.length;i++){var iName=invKeys[i];var iData=inv[iName];var qty=typeof iData==='object'?iData.数量||1:iData;items.push({name:iName,desc:'x'+qty})}}
  showPickModal('选择着装 - '+slot,items,function(item){
    if(item.name==='卸下(空置)'){
      var gearName=getProp(window.cachedData,'主角.着装.'+slot,'')||'';
      window.pendingActions.push({desc:'卸下'+slot+'装备'+(gearName?'：'+gearName:''),cmd:'/setvar 主角.着装.'+slot+' ""|/trigger'});
      if(gearName){window.pendingActions.push({desc:'将'+gearName+'放回背包',cmd:'/send '+slot+'脱下'+gearName+'，请回复时在 <UpdateVariable> 的 JSONPatch 中 add /主角/背包/'+gearName+'|/trigger'})}
      updateHijack();setTimeout(renderAll,300)}
    else{window.pendingActions.push({desc:'装备'+item.name+'到'+slot,cmd:'/setvar 主角.着装.'+slot+' "'+item.name.replace(/"/g,'\\"')+'"|/trigger'});window.pendingActions.push({desc:'将'+item.name+'从背包移除',cmd:'/setvar 主角.背包.'+item.name+' null|/trigger'});updateHijack();setTimeout(renderAll,300)}
  });
};
window.editHeroString=function(label,elId){var el=document.getElementById(elId);var cur=el.textContent==='-'?'':el.textContent;var keyMap={战斗定位:'战斗定位',当前情绪:'当前情绪'};var key=keyMap[label];if(!key)return;var val=prompt('编辑'+label,cur);if(val===null)return;window.pendingActions.push({desc:'修改主角'+label+'为 '+val,cmd:'/setvar 主角.'+key+' "'+val.replace(/"/g,'\\"')+'"|/trigger'});updateHijack();setTimeout(renderAll,300)};
window.editHeroNumber=function(label,elId){var el=document.getElementById(elId);var cur=el.textContent==='-'?'':el.textContent;var keyMap={以太适应性:'以太适应性'};var key=keyMap[label];if(!key)return;var val=prompt('编辑'+label+' (0-100)',cur);if(val===null)return;var num=parseInt(val);if(isNaN(num)||num<0||num>100){alert('请输入0-100的数字');return}window.pendingActions.push({desc:'修改主角'+label+'为 '+num,cmd:'/setvar 主角.'+key+' '+num+'|/trigger'});updateHijack();setTimeout(renderAll,300)};
window.addHeroItem=function(){var nameEl=document.getElementById('inv-new-name');var qtyEl=document.getElementById('inv-new-qty');var name=nameEl.value.trim();var qty=parseInt(qtyEl.value)||1;if(!name)return;window.pendingActions.push({desc:'添加道具 '+name+' x'+qty,cmd:'/setvar 主角.背包.'+name+' '+qty+'|/trigger'});updateHijack();nameEl.value='';qtyEl.value='1';setTimeout(renderAll,300)};
window.editHeroItem=function(name,qty){var newName=prompt('物品名',name);if(!newName)return;var newQty=parseInt(prompt('数量',qty))||0;if(newQty<=0){if(confirm('删除物品 ['+newName+'] ？')){window.pendingActions.push({desc:'删除道具 '+newName,cmd:'/setvar 主角.背包.'+newName+' null|/trigger'});updateHijack()}}else{window.pendingActions.push({desc:'修改道具 '+newName+' 数量为 '+newQty,cmd:'/setvar 主角.背包.'+newName+' '+newQty+'|/trigger'});updateHijack()}setTimeout(renderAll,300)};

function renderFactions(data){var fc=document.getElementById('faction-container');if(!data){fc.innerHTML='<div class="nodata">暂无阵营数据</div>';return}var FNS=['狡兔屋','对空六课','白祇重工','维多利亚家政','卡吕冬之子','治安局','天琴座','云岿山'];var factions={};FNS.forEach(function(f){var val=getProp(data,'阵营.'+f,getProp(data,'factions.'+f,0));var title=getProp(data,'阵营.'+f+'_称号',getProp(data,'factions.'+f+'_称号',''))||getFactionTitle(val);var quest=getProp(data,'阵营.'+f+'_委托',getProp(data,'factions.'+f+'_委托',false));factions[f]={val:val,title:title,quest:quest}});var html='';var factionKeys=Object.keys(factions);for(var i=0;i<factionKeys.length;i++){var name=factionKeys[i];var f=factions[name];var visualPct=Math.max(0,Math.min(100,((f.val+100)/2)|0));html+='<div style="margin-bottom:10px;border-bottom:1px dashed rgba(255,255,255,.04);padding-bottom:8px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px"><span style="font-size:13px;font-weight:600;color:var(--text)">'+name+'</span><span style="font-size:11px;color:var(--muted)">'+f.title+' · '+f.val+' '+(f.quest?'🟢':'⚪')+'</span></div><div style="height:6px;background:rgba(255,255,255,.05);border-radius:3px;overflow:hidden"><div style="height:100%;width:'+visualPct+'%;background:'+(f.val<0?'var(--danger)':'var(--green)')+';border-radius:3px;transition:width .5s"></div></div></div>'}fc.innerHTML=html||'<div class="nodata">暂无阵营数据</div>'}
function getFactionTitle(v){if(v<=-51)return '仇敌';if(v<=-11)return '冷淡';if(v<=10)return '陌生人';if(v<=50)return '朋友';if(v<=80)return '盟友';return '至交'}

function renderOwnedBangboos(data){var list=document.getElementById('owned-bangboo-list');var owned=getProp(data,'邦布.拥有的邦布',getProp(data,'bangboo.拥有的邦布',[]));var partner=getProp(data,'邦布.邦布伙伴',getProp(data,'bangboo.邦布伙伴',''));if(!Array.isArray(owned)||owned.length===0){list.innerHTML='<div class="nodata" style="grid-column:1/-1">暂无拥有邦布</div>';return}var html='';owned.forEach(function(bbName){var info=ALL_BANGBOOS.find(function(b){return b.name===bbName})||{faction:'?',skill:'?'};var isActive=(partner===bbName);html+='<div class="npc-g-card" onclick="'+(isActive?'':'swapBangboo(\''+bbName+'\')')+'" style="'+(isActive?'border-color:var(--orange);background:rgba(255,167,38,.08)':'')+';cursor:'+(isActive?'default':'pointer')+'"><span class="npc-g-label" style="color:'+(isActive?'var(--orange)':'var(--muted)')+'">'+(isActive?'★ 已携带':info.faction)+'</span><span class="npc-g-val" style="font-size:12px">'+bbName+'</span><span style="font-size:10px;color:var(--muted);display:block;margin-top:2px">'+info.skill+'</span>'+(isActive?'':'<span style="font-size:9px;color:var(--gold);display:block;margin-top:3px">点击携带</span>')+'</div>'});list.innerHTML=html}
function renderBangbooGallery(data){var gallery=document.getElementById('bangboo-gallery');var owned=getProp(data,'邦布.拥有的邦布',getProp(data,'bangboo.拥有的邦布',[]));var partner=getProp(data,'邦布.邦布伙伴',getProp(data,'bangboo.邦布伙伴',''));var html='';ALL_BANGBOOS.forEach(function(bb){var isOwned=Array.isArray(owned)&&owned.includes(bb.name);var isActive=(partner===bb.name);html+='<div class="npc-g-card" style="'+(isActive?'border-color:var(--orange);background:rgba(255,167,38,.08)':isOwned?'border-color:var(--green)':'')+'"><span class="npc-g-label" style="color:'+(isActive?'var(--orange)':isOwned?'var(--green)':'var(--muted)')+'">'+(isActive?'★ 携带中':isOwned?'✓ 已拥有':bb.faction)+'</span><span class="npc-g-val" style="font-size:12px">'+bb.name+'</span><span style="font-size:10px;color:var(--muted);display:block;margin-top:2px">'+bb.skill+'</span></div>'});gallery.innerHTML=html}
window.isInHollow=function(){var sd=window.cachedData;if(!sd)return false;var h=getProp(sd,'空洞.当前空洞','');return h&&h!==''&&h!=='（不在空洞中）';};
window.swapBangboo=function(name){if(window.isInHollow()){alert('⚠️ 当前处于空洞探索中，无法更换邦布伙伴。请先退出空洞。');return}if(confirm('确定要将邦布伙伴替换为 「'+name+'」 吗？')){window.pendingActions.push({desc:'切换邦布伙伴为 '+name,cmd:'/setvar 邦布.邦布伙伴 "'+name+'"|/trigger'});updateHijack();setTimeout(renderAll,300)}};
window.unselectBangboo=function(name){if(window.isInHollow()){alert('⚠️ 当前处于空洞探索中，无法取消携带邦布。请先退出空洞。');return}if(confirm('确定要取消携带 「'+name+'」 吗？')){window.pendingActions.push({desc:'取消携带邦布 '+name,cmd:'/setvar 邦布.邦布伙伴 remove "'+name+'"|/trigger'});updateHijack();setTimeout(renderAll,300)}};
window.addBangboo=function(){if(window.isInHollow()){alert('⚠️ 当前处于空洞探索中，无法添加邦布。请先退出空洞。');return}var nameEl=document.getElementById('bb-new-name');var name=nameEl.value.trim();if(!name)return;window.pendingActions.push({desc:'添加邦布 '+name+'（不自动携带）',cmd:'/setvar 邦布.拥有的邦布 add "'+name+'"|/trigger'});updateHijack();nameEl.value='';document.getElementById('bb-new-faction').value='';document.getElementById('bb-new-skill').value='';setTimeout(renderAll,300)};

function renderQuests(data){var qc=document.getElementById('quest-container');if(!data){qc.innerHTML='<div class="nodata">暂无任务数据</div>';return}var active=getProp(data,'任务.已激活',[]);var details=getProp(data,'任务.详情',{});if(!active.length){qc.innerHTML='<div class="nodata">暂无激活任务</div>';return}var html='';active.forEach(function(name){var d=details[name]||{};var status=d.状态||'未知';var client=d.委托人||'';var reward=d.报酬||'';var clues=d.线索||[];var sc=status==='已完成'?'var(--green)':status==='进行中'?'var(--gold)':'var(--muted)';html+='<div class="card"><h3><span class="dot" style="background:'+sc+'"></span>'+name+' <span style="font-weight:400;font-size:11px;color:'+sc+'">· '+status+'</span></h3><div class="kv-row"><span style="color:var(--muted)">委托人</span><span class="kv-v" style="color:var(--gold)">'+client+'</span></div><div class="kv-row"><span style="color:var(--muted)">报酬</span><span class="kv-v" style="color:var(--green)">'+reward+'</span></div>';if(clues.length>0){html+='<div style="margin-top:8px"><span style="font-size:11px;color:var(--pink);font-weight:600">🔍 线索</span>';clues.forEach(function(c){html+='<div style="font-size:11px;color:var(--text);margin:4px 0 0 12px;padding:4px 0;border-bottom:1px dashed rgba(255,255,255,.04)">▸ '+c+'</div>'});html+='</div>'}html+='</div>'});qc.innerHTML=html}

renderAll();
if(typeof eventOn==='function'&&typeof Mvu!=='undefined'){try{eventOn(Mvu.events.VARIABLE_UPDATE_ENDED,function(){setTimeout(renderAll,200)})}catch(e){}}
</script>
</body>
</html>

